sys_sg_data_item.query_condition_script:
(function(input) {
    const userID       = gs.getUserID();
    var   grOUsWhereTA = new GlideRecord('x_153465_discovert_discover_office_members');
    grOUsWhereTA.addQuery('office_member', userID);
    grOUsWhereTA.addQuery('office_task_authority', 'true');
    grOUsWhereTA.query();

    var ous = [];
    while (grOUsWhereTA.next()) {
        ous.push(grOUsWhereTA.getValue('discover_office_hierarchy'));
    }
    return "u_status=In progress^u_request_type=Reassignment^parent.active=true^parent.reassignment_requested=true^parent.stateIN13^parent.primary_assigneeIN" + ous.join(",");
})(input);
